// ═══ Auth integration ═══
function getKitabhUser() {
  const u = typeof window !== "undefined" ? (window as any).__KITABH_USER : undefined
  return {
    authenticated: u?.authenticated === true,
    premium: u?.premium === true,
    email: u?.email || "",
    token: u?.token || ""
  }
}

